          {id:"sap-n4",name:"Otaru Day Trip (Canal + Glass Quarter)",lat:43.199041,lng:141.0021176,rating:4.4,price_low:20,price_high:50,blurb:"Historic canal port 45 min by JR (about 750 yen each way). Preserved brick warehouses, music box museum, glass shops, good lunch spots.",why:"Easy half or full-day side trip.",place_id:"ChIJ0UxVV2ThCl8RIZdpda0H7gQ"}
