          {id:"seo-b3",name:"Bogwangjung Itaewon (pork belly specialist)",lat:37.5333181,lng:126.9945515,rating:4.9,price_low:30,price_high:55,blurb:"4.9 star samgyeopsal joint. Chef cooks at the table and coaches you through the meal. Book ahead.",why:"Best pork belly experience in Seoul.",place_id:"ChIJnbqVZSSjfDURXy6xhCsHEN8",images:["images/seoul/seo-b3-1.jpg","images/seoul/seo-b3-2.jpg","images/seoul/seo-b3-3.jpg"]},
          {id:"seo-b4",name:"MapleTree House Itaewon (galbi)",lat:37.535049,lng:126.9939672,rating:4.3,price_low:50,price_high:90,blurb:"Upscale galbi specialist. Jeju black pork also excellent. English-friendly staff.",why:"Most refined KBBQ option.",place_id:"ChIJP1IxUUqifDUR2NBF3aY0UUs",images:["images/seoul/seo-b4-1.jpg","images/seoul/seo-b4-2.jpg","images/seoul/seo-b4-3.jpg"]},
          {id:"seo-mp1",name:"Mapo Galmaegi KBBQ",lat:37.5487,lng:126.9524,rating:4.4,price_low:20,price_high:40,blurb:"Thinly sliced pork neck (galmaegi-sal) grilled at the table: leaner, cheaper and more intensely flavoured than belly, beloved by Seoul regulars. Mapo has a concentration of galmaegi-sal specialists.",why:"Local-favourite cut most tourists miss; cheaper than samgyeopsal."}
