          {id:"seo-cf5",name:"943 Kings Cross (Harry Potter cafe)",lat:37.5529807,lng:126.9208140,rating:4.7,price_low:15,price_high:25,blurb:"Multi-floor Harry Potter themed cafe: interactive elements, alcoholic butter beer, Hagrid cake.",why:"Quirky non-cat alternative.",place_id:"ChIJEadTU22ZfDUR5a0eGJIKQnA",images:["images/seoul/seo-cf5-1.jpg","images/seoul/seo-cf5-2.jpg","images/seoul/seo-cf5-3.jpg"]},
          {id:"seo-cf6",name:"Stylenanda Pink Pool Cafe",lat:37.5545473,lng:126.9274387,rating:4.0,price_low:10,price_high:18,blurb:"Top floor of Stylenanda flagship. Pink everything. Pool may or may not be operational. Drinks average but the space is the point.",why:"From your original plan; photo destination.",place_id:"ChIJK5kufMGYfDUR6DOKgF9uILk",images:["images/seoul/seo-cf6-1.jpg","images/seoul/seo-cf6-2.jpg","images/seoul/seo-cf6-3.jpg"]},
          {id:"seo-cf7",name:"Thanks Nature Cafe (Sheep Cafe, Hongdae)",lat:37.5556679,lng:126.9235374,rating:4.2,price_low:8,price_high:14,blurb:"Two real sheep live in a pen outside this Hongdae basement cafe. Pet them, then have a waffle and latte inside. Free to visit with a drink order.",why:"Pure novelty; the only sheep cafe in Seoul.",place_id:"",images:["images/seoul/seo-cf7-1.jpg","images/seoul/seo-cf7-2.jpg","images/seoul/seo-cf7-3.jpg"]},
          {id:"seo-cf8",name:"Cafe Onion Anguk (Hanok Bakery Cafe)",lat:37.5765577,lng:126.9856024,rating:4.4,price_low:6,price_high:14,blurb:"A century-old hanok turned stunning bakery-cafe between Gyeongbokgung and Changdeokgung. Courtyard seating, floor cushions, and trays of just-baked bread — get the sugar-dusted 'pandoro'.",why:"Most beautiful cafe in the old city; pairs with a palace day.",place_id:"",images:["images/seoul/seo-cf8-1.jpg","images/seoul/seo-cf8-2.jpg","images/seoul/seo-cf8-3.jpg"]},
          {id:"seo-ir4",name:"O'Kitchen (Hannam brunch cafe)",lat:37.5365,lng:127.0010,rating:4.5,price_low:14,price_high:22,blurb:"Hannam beloved brunch-and-lunch cafe: open-face sandwiches, grain bowls and weekend egg dishes in a light-filled room. A neighbourhood institution.",why:"Best sit-down brunch in Hannam; earned rather than just Instagram-famous."},
          {id:"seo-ir5",name:"Tartine Hannam (sourdough bakery)",lat:37.5364,lng:127.0008,rating:4.4,price_low:9,price_high:16,blurb:"A Korean outpost of San Francisco legendary sourdough bakery, in a striking minimalist Hannam space. Country bread, morning buns and very good coffee.",why:"Best bread in Seoul; worth the detour from Itaewon."},
          {id:"seo-sc1",name:"Fritz Coffee Company (Seongsu)",lat:37.5456,lng:127.0352,rating:4.6,price_low:6,price_high:12,blurb:"One of Seoul finest specialty roasters, in a beautifully converted Seongsu warehouse. Direct-trade lots, precise extraction and cinnamon rolls that sell out by 11am.",why:"The cafe that defines Seoul specialty coffee; a must-visit in Seongsu."},
          {id:"seo-sc3",name:"Daelim Changgo (Seongsu warehouse cafe)",lat:37.5445,lng:127.0363,rating:4.3,price_low:6,price_high:10,blurb:"A 1960s factory warehouse transformed into a multi-level cafe and art space: exposed brick, skylights and a sprawling outdoor terrace. The most atmospheric hangout in Seongsu.",why:"Best cafe atmosphere in Seongsu; the warehouse-industrial vibe at its best."},
          {id:"seo-sc4",name:"Able (Seongsu Korean fusion brunch)",lat:37.5440,lng:127.0370,rating:4.4,price_low:12,price_high:18,blurb:"A chic Seongsu brunch spot blending Korean and Western flavours: doenjang-glazed chicken plates, grain bowls and excellent lattes in a Scandi-meets-Seoul dining room.",why:"Best lunch in Seongsu after Seoul Forest."},
          {id:"seo-ant1",name:"Anthracite Hongdae (specialty coffee)",lat:37.5565,lng:126.9248,rating:4.5,price_low:5,price_high:10,blurb:"A converted shoe factory turned landmark specialty coffee shop: exposed industrial bones, 7m ceilings and outstanding single-origin pour-overs roasted in-house. Seoul most photographed coffee interior.",why:"The Hongdae cafe that launched Seoul specialty-coffee scene."},
          {id:"seo-ins2",name:"Cafe Bora (Bukchon, matcha)",lat:37.5808,lng:126.9833,rating:4.4,price_low:8,price_high:14,blurb:"An iconic Bukchon cafe famous for vibrant purple-rice tteok latte and matcha soft-serve, served in a tiny hanok room near the village entrance. Always a queue but moves fast.",why:"Most photogenic cafe in the old city; earns its reputation."}
